 12→const decorateProfileUser = (user) => {
 13→    if(!user){
 14→        return user;
 15→    }
 16→
 17→    const avatarMedia = createMediaResponsePayload('avatars', user.image_url, 'detail');
 18→    return {
 19→        ...user,
 20→        image_url: avatarMedia?.preferred_url || user.image_url || null,
 21→        avatar_media: avatarMedia
 22→    };
