372→export const updateJournalService = async(content, title, journalId, userId) => {
373→    if(!journalId){
374→        console.error('journalid is undefined');
375→        throw {status: 400, error: 'journalId is undefined'}
376→    }
377→
378→    if(!userId){
379→        console.error('userId is undefined')
380→        throw({status: 400, error: 'userId is undefined'})
381→    }
382→
383→    const {data: existingJournal, error: existingJournalError} = await supabase
384→    .from('journals')
385→    .select('id, user_id, content, title, post_type')
386→    .eq('id', journalId)
387→    .eq('user_id', userId)
388→    .maybeSingle();
389→
390→    if(existingJournalError){
391→        console.error('failed to fetch existing journal for update', existingJournalError.message);
392→        throw {status: 500, error: 'failed to fetch existing journal for update'};
393→    }
394→
395→    if(!existingJournal){
396→        console.error('journal not found for update');
397→        throw {status: 404, error: 'journal not found for update'};
398→    }
399→
400→    const resolvedTitle = typeof title === 'string' && title.trim() ? title.trim() : existingJournal.title;
401→    if(!resolvedTitle){
402→        console.error('title is undefined');
403→        throw {status: 400, error: 'title is undefined'};
404→    }
405→
406→    let resolvedContent = existingJournal.content;
407→    if(typeof content === 'string' && content.trim()){
408→        resolvedContent = content;
409→    }
410→
411→    if(!resolvedContent){
412→        console.error('text content is missing for text post update');
413→        throw {status: 400, error: 'text content is missing for text post update'};
414→    }
415→
416→    const parseData = parseTextContentSafely(resolvedContent);
417→    if(!parseData){
418→        console.error('failed to parse text content for update');
419→        throw {status: 400, error: 'failed to parse text content for update'};
420→    }
421→
422→    const embeddingBody = parseData.wholeText || '';
423→    const preview_text = parseData.slicedText || '';
424→    const thumbnail_url = parseData.firstImage?.src || null;
425→    const embeddings = await GenerateEmbeddings(resolvedTitle, embeddingBody);
426→
427→    if(!embeddings || !Array.isArray(embeddings) || embeddings.length === 0){
428→        console.error('failed to generate embeddings')
429→        throw {status: 400, error: 'failed to generate embeddings'};
430→    }
431→
432→    const journalData = {
433→        content: resolvedContent,
434→        title: resolvedTitle,
435→        post_type: POST_TYPE_TEXT,
436→        embeddings: embeddings,
437→        preview_text,
438→        thumbnail_url,
439→    }
440→
441→    const {data, error} = await supabase
442→    .from('journals')
443→    .update(journalData)
444→    .eq('id', journalId)
445→    .eq('user_id', userId)
446→
447→    if(error){
448→        console.error('supabase error while uploading content:', error.message);
449→        throw{status: 500, error: 'supabase error while uploading content'};
450→    }
451→
452→    // Non-fatal: send mention notifications on edit
453→    try {
454→        const mentionedUserIds = extractMentionUserIds(resolvedContent);
455→        const filtered = mentionedUserIds
456→            .filter(id => id !== userId)
457→            .slice(0, 50);
458→
459→        // Remove old mention notifications for this journal to avoid duplicates
460→        const { error: deleteError } = await supabase
461→            .from('notifications')
462→            .delete()
463→            .eq('type', 'mention')
464→            .eq('journal_id', journalId);
465→
466→        if (deleteError) console.error('[mentions] edit: clear old failed:', deleteError.message);
467→
468→        if (filtered.length > 0) {
469→            const notifRows = filtered.map(receiverId => ({
470→                sender_id: userId,
471→                receiver_id: receiverId,
472→                type: 'mention',
473→                journal_id: journalId,
474→                read: false
475→            }));
476→
477→            const { error: notifError } = await supabase
478→                .from('notifications')
479→                .insert(notifRows);
480→
481→            if (notifError) console.error('[mentions] edit: insert failed:', notifError.message);
482→        }
483→    } catch (mentionErr) {
484→        console.error('[mentions] edit error:', mentionErr?.message || mentionErr);
485→    }
486→
487→    return true;
488→}
