306→const resolveMediaUrl = async(bucket, path) => {
307→    const {data: publicUrlData} = supabase.storage
308→        .from(bucket)
309→        .getPublicUrl(path);
310→
311→    const publicUrl = publicUrlData?.publicUrl || null;
312→    if(publicUrl){
313→        return publicUrl;
314→    }
315→
316→    const {data: signedUrlData, error: signedUrlError} = await supabase.storage
317→        .from(bucket)
318→        .createSignedUrl(path, 60 * 60);
319→
320→    if(!signedUrlError && signedUrlData?.signedUrl){
321→        return signedUrlData.signedUrl;
322→    }
323→
324→    return null;
325→};
