374→const hydrateMediaItems = async(items) => {
375→    if(!Array.isArray(items) || items.length === 0){
376→        return [];
377→    }
378→
379→    const hydrated = await Promise.all(items.map(async(item) => {
380→        const url = await resolveMediaUrl(item.bucket, item.path);
381→        if(!url){
382→            return null;
383→        }
384→
385→        const mediaPayload = createMediaResponsePayload(item.bucket, url, 'card');
386→
387→        return {
388→            id: `${item.bucket}-${mediaPayload?.path || item.path}`,
389→            bucket: item.bucket,
390→            path: mediaPayload?.path || item.path,
391→            name: item.name,
392→            createdAt: item.createdAt || null,
393→            timestamp: item.timestamp || 0,
394→            url: mediaPayload?.preferred_url || url,
395→            thumbnailUrl: mediaPayload?.thumbnail_url || url,
396→            cardUrl: mediaPayload?.card_url || url,
397→            detailUrl: mediaPayload?.detail_url || url,
398→            originalUrl: mediaPayload?.original_url || url
399→        };
400→    }));
401→
402→    return hydrated.filter(Boolean);
403→};
