 59→export const deleteJournalImageService = async(userId, filepath) =>{
 60→    if(!userId){
 61→        console.error('userId is undefined');
 62→        throw {status: 400, error:'userId is undefined'};
 63→    }
 64→    
 65→    if(!filepath){
 66→        console.error('filepath is undefined');
 67→        throw {status: 400, error: 'filepath is undefined'}
 68→    }
 69→
 70→    const normalizedPaths = (Array.isArray(filepath) ? filepath : [filepath])
 71→        .filter((path) => typeof path === 'string' && path.trim())
 72→        .flatMap((path) => listVariantPathsForDeletion(path.trim()));
 73→
 74→    if(normalizedPaths.length === 0){
