 52→/**
 53→ * Bootstrap topic_embeddings table at server start.
 54→ * Generates embeddings for any missing topics and loads all into the in-memory cache.
 55→ */
 56→export const bootstrapTopicEmbeddings = async () => {
 57→    // Fetch existing topic embeddings
 58→    const { data: existing, error: fetchError } = await supabase
 59→        .from('topic_embeddings')
 60→        .select('topic, embedding');
 61→
 62→    if (fetchError) {
 63→        console.error('Failed to fetch topic_embeddings:', fetchError.message);
 64→        return;
 65→    }
 66→
 67→    const existingTopics = new Set((existing || []).map(r => r.topic));
 68→
 69→    // Load existing into cache
 70→    for (const row of (existing || [])) {
 71→        topicEmbeddingCache.set(row.topic, row.embedding);
 72→    }
 73→
 74→    // Find missing topics
 75→    const missing = CANONICAL_TOPICS.filter(t => !existingTopics.has(t));
 76→
 77→    if (missing.length > 0) {
 78→        console.log(`topic_embeddings: generating ${missing.length} missing embeddings...`);
 79→
 80→        for (const topic of missing) {
 81→            try {
 82→                const embedding = await GenerateEmbeddings(topic, '');
 83→                if (!embedding) {
 84→                    console.error(`  Failed to generate embedding for topic "${topic}"`);
 85→                    continue;
 86→                }
 87→
 88→                const { error: insertError } = await supabase
 89→                    .from('topic_embeddings')
 90→                    .upsert({ topic, embedding }, { onConflict: 'topic' });
 91→
 92→                if (insertError) {
 93→                    console.error(`  Failed to insert topic "${topic}":`, insertError.message);
 94→                } else {
 95→                    topicEmbeddingCache.set(topic, embedding);
 96→                }
 97→            } catch (err) {
 98→                console.error(`  Error generating embedding for topic "${topic}":`, err.message);
 99→            }
100→        }
101→    }
102→
103→    console.log(`topic_embeddings: all topics present (${topicEmbeddingCache.size} cached)`);
104→};
105→
106→/**
107→ * Get the cached embedding for a topic.
108→ * Returns null if not cached (topic was never bootstrapped or failed).
109→ */
110→export const getTopicEmbedding = (topic) => {
111→    return topicEmbeddingCache.get(topic) || null;
112→};
