518→router.get('/getUnreadNotification', requireAuth, async(req, res) => {
519→    const {before} = req.query;
520→
521→    const parsedLimit = parseLimitWithinRange(
522→        req.query.limit,
523→        NOTIFICATION_LIMIT_MIN,
524→        NOTIFICATION_LIMIT_MAX,
525→        NOTIFICATION_DEFAULT_LIMIT
526→    );
527→
528→    if(parsedLimit == null){
529→        return res.status(400).json({error: `limit must be between ${NOTIFICATION_LIMIT_MIN} and ${NOTIFICATION_LIMIT_MAX}`});
530→    }
531→
532→    const receiverId = req.userId;
533→    const fetchLimit = parsedLimit + 1;
534→
535→    let journalQuery = supabase
536→    .from('notifications')
537→    .select(NOTIFICATION_JOURNAL_SELECT)
538→    .eq('receiver_id', receiverId)
539→    .eq('read', false)
540→    .order('created_at', {ascending: false})
541→    .order('id', {ascending: false})
542→    .limit(fetchLimit)
543→
544→    let opinionQuery = supabase
545→    .from('notification_opinions')
546→    .select(NOTIFICATION_OPINION_SELECT)
547→    .eq('receiver_id', receiverId)
548→    .eq('read', false)
549→    .order('created_at', {ascending: false})
550→    .order('id', {ascending: false})
551→    .limit(fetchLimit)
552→
553→    if(before){
554→        journalQuery = journalQuery.lt('created_at', before);
555→        opinionQuery = opinionQuery.lt('created_at', before);
556→    }
557→
558→    const [journalResult, opinionResult] = await Promise.all([journalQuery, opinionQuery]);
559→
560→    if(journalResult.error){
561→        console.error('supabase error:', journalResult.error.message);
562→        return res.status(500).json({error: 'supabase error while getting unread notification'})
563→    }
564→    if(opinionResult.error){
565→        console.error('supabase error:', opinionResult.error.message);
566→        return res.status(500).json({error: 'supabase error while getting unread opinion notification'})
567→    }
568→
569→    const journalNotifs = (journalResult.data || []).map(n => ({...n, source: 'journal'}));
570→    const opinionNotifs = (opinionResult.data || []).map(n => ({...n, source: 'opinion'}));
571→
572→    const merged = [...journalNotifs, ...opinionNotifs]
573→        .sort((a, b) => new Date(b.created_at) - new Date(a.created_at));
574→
575→    const journalIds = [...new Set(
576→        merged
577→            .filter((n) => n.source === 'journal')
578→            .map((n) => n.journal_id)
579→            .filter(Boolean)
580→    )];
581→
582→    let hasLikedResult = [];
583→    let hasBookMarkedResult = [];
584→    if(journalIds.length > 0){
585→        const [hasLiked, hasBookMarked] = await Promise.all([
586→            supabase.from('likes').select('journal_id').eq('user_id', receiverId).in('journal_id', journalIds),
587→            supabase.from('bookmarks').select('journal_id').eq('user_id', receiverId).in('journal_id', journalIds)
588→        ]);
