590→        if(hasLiked.error || hasBookMarked.error){
591→            console.error('error', hasLiked.error || hasBookMarked.error)
592→            return res.status(500).json({error: 'supabase error on likes or bookmarks table'})
593→        }
594→        hasLikedResult = hasLiked.data || [];
595→        hasBookMarkedResult = hasBookMarked.data || [];
596→    }
597→
598→    const userHasLikedSet = new Set(hasLikedResult.map((like) => like.journal_id));
599→    const userHasBookmarkedSet = new Set(hasBookMarkedResult.map((bookmark) => bookmark.journal_id));
600→
601→    const formatted = merged.map((notification) => decorateNotificationMedia({
602→        ...notification,
603→        hasLiked: notification.source === 'journal' ? userHasLikedSet.has(notification?.journal_id) : false,
604→        hasBookMarked: notification.source === 'journal' ? userHasBookmarkedSet.has(notification?.journal_id) : false
605→    }))
606→
607→    const hasMore = formatted.length > parsedLimit;
608→    const slicedData = hasMore ? formatted.slice(0, parsedLimit) : formatted;
609→
610→    return res.status(200).json({
611→        data: slicedData,
612→        hasMore: hasMore
613→    })
