 974→    if (!username || typeof username !== 'string') {
 975→        return res.status(400).json({ error: 'username is required' });
 976→    }
 977→
 978→    const trimmed = username.trim();
 979→    if (trimmed.length < 3 || trimmed.length > 50) {
 980→        return res.status(400).json({ error: 'username must be 3-50 characters' });
 981→    }
 982→
 983→    if (!/^[a-zA-Z0-9-]+$/.test(trimmed)) {
 984→        return res.status(400).json({ error: 'username can only contain letters, numbers, and hyphens' });
 985→    }
 986→
 987→    const normalized = trimmed.toLowerCase();
 988→    const RESERVED_WORDS = ['admin', 'root', 'iskrib', 'iskryb', 'support', 'help', 'api', 'www', 'null', 'undefined'];
 989→    if (RESERVED_WORDS.includes(normalized)) {
 990→        return res.status(400).json({ error: 'this username is reserved' });
 991→    }
 992→
 993→    // Check uniqueness
 994→    const { data: existing } = await supabase
 995→        .from('users')
 996→        .select('id')
 997→        .ilike('username', normalized)
 998→        .neq('id', userId)
 999→        .limit(1);
1000→
1001→    if (existing && existing.length > 0) {
1002→        return res.status(409).json({ error: 'username is already taken' });
1003→    }
1004→
1005→    const { error: updateError } = await supabase
1006→        .from('users')
1007→        .update({ username: trimmed.toLowerCase() })
1008→        .eq('id', userId);
1009→
1010→    if (updateError) {
1011→        console.error('update-username error:', updateError.message);
1012→        return res.status(500).json({ error: 'failed to update username' });
1013→    }
1014→
1015→    return res.status(200).json({ message: 'success', username: trimmed.toLowerCase() });
1016→});
